// ============================================================
// CONFIG — edit everything in the "Prompt Config" Set node
// api_key | model | concurrency | limit (0=all) | output_column
// ============================================================
const cfg         = items[0].json;
const API_KEY     = cfg.api_key;
const MODEL       = cfg.model;
const CONCURRENCY = Number(cfg.concurrency) || 100;
const PROMPT_BASE = cfg.prompt_instructions;
const OUT_COL     = cfg.output_column || 'Personalisation';
const LIMIT       = Number(cfg.limit) || 0;

const toProcess = LIMIT > 0 ? items.slice(0, LIMIT) : items;

// ============================================================
// Run fn over array with max concLimit parallel promises
// ============================================================
async function withConcurrency(arr, concLimit, fn) {
  const out = new Array(arr.length);
  let i = 0;
  async function worker() {
    while (i < arr.length) {
      const idx = i++;
      out[idx] = await fn(arr[idx], idx);
    }
  }
  const workers = Array.from({ length: Math.min(concLimit, arr.length) }, worker);
  await Promise.all(workers);
  return out;
}

// ============================================================
// Single OpenRouter call
// ============================================================
async function callOpenRouter(item) {
  const summary = (item.json['Website Summary'] || '').trim();
  const desc    = (item.json['Company Short Description'] || '').trim();
  const prompt  = PROMPT_BASE + '\n\n' + summary + '\n\n' + desc;

  const resp = await fetch('https://openrouter.ai/api/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + API_KEY,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: MODEL,
      messages: [{ role: 'user', content: prompt }],
      temperature: 0.8,
      max_tokens: 150,
    }),
  });

  if (!resp.ok) {
    throw new Error('OpenRouter ' + resp.status + ': ' + await resp.text());
  }

  const data = await resp.json();
  return data.choices[0].message.content.trim();
}

// ============================================================
// Main
// ============================================================
const results = await withConcurrency(toProcess, CONCURRENCY, async (item) => {
  try {
    const icebreaker = await callOpenRouter(item);
    return {
      json: {
        row_number: item.json.row_number,
        [OUT_COL]:  icebreaker,
      }
    };
  } catch (e) {
    return {
      json: {
        row_number: item.json.row_number,
        [OUT_COL]:  '',
        _error:     e.message,
      }
    };
  }
});

return results;
